import { z } from "zod";
import { performance } from "perf_hooks";

// Hypothetical AI SDK import (replace with actual SDK)
import { Skill, SkillInput, SkillOutput } from "ai-sdk";

// Define the benchmark schema
const BenchmarkSchema = z.object({
  id: z.string(),
  input: z.any(),
  expectedOutput: z.any(),
});

// TypeScript types inferred from schema
type Benchmark = z.infer<typeof BenchmarkSchema>;

// Grading function: simple deep equality check (can be replaced)
function gradeOutput(expected: any, actual: any): boolean {
  return JSON.stringify(expected) === JSON.stringify(actual);
}

// Result type
interface EvalResult {
  benchmarkId: string;
  success: boolean;
  timeMs: number;
  expectedOutput: any;
  actualOutput: any;
}

// Offline evaluation runner class
export class OfflineEvalRunner {
  private skill: Skill;
  private benchmarks: Benchmark[];

  constructor(skill: Skill, benchmarks: unknown[]) {
    this.skill = skill;
    // Validate benchmarks
    this.benchmarks = benchmarks.map((b, i) => {
      const parsed = BenchmarkSchema.safeParse(b);
      if (!parsed.success) {
        throw new Error(`Benchmark at index ${i} failed validation: ${parsed.error}`);
      }
      return parsed.data;
    });
  }

  async run(): Promise<EvalResult[]> {
    const results: EvalResult[] = [];

    for (const benchmark of this.benchmarks) {
      const start = performance.now();

      // Run the skill with the input
      let actualOutput: any;
      try {
        actualOutput = await this.skill.invoke(benchmark.input as SkillInput);
      } catch (err) {
        actualOutput = { error: (err as Error).message };
      }

      const end = performance.now();
      const timeMs = end - start;

      // Grade the output
      const success = gradeOutput(benchmark.expectedOutput, actualOutput);

      results.push({
        benchmarkId: benchmark.id,
        success,
        timeMs,
        expectedOutput: benchmark.expectedOutput,
        actualOutput,
      });
    }

    return results;
  }

  static printSummary(results: EvalResult[]) {
    const total = results.length;
    const passed = results.filter((r) => r.success).length;
    const failed = total - passed;
    const avgTime = results.reduce((acc, r) => acc + r.timeMs, 0) / total;

    console.log("=== Offline Evaluation Summary ===");
    console.log(`Total benchmarks: ${total}`);
    console.log(`Passed: ${passed}`);
    console.log(`Failed: ${failed}`);
    console.log(`Average time per run: ${avgTime.toFixed(2)} ms`);
    console.log("");

    results.forEach((r) => {
      console.log(`Benchmark ID: ${r.benchmarkId}`);
      console.log(`  Success: ${r.success}`);
      console.log(`  Time: ${r.timeMs.toFixed(2)} ms`);
      if (!r.success) {
        console.log(`  Expected: ${JSON.stringify(r.expectedOutput)}`);
        console.log(`  Actual:   ${JSON.stringify(r.actualOutput)}`);
      }
      console.log("");
    });
  }
}
```

